from typing import List
from math import isqrt
from collections import defaultdict

class Solution:
    def maximumSum(self, nums: List[int]) -> int:
        # Reduce each number to its square-free core:
        # x = core * t^2  => core has no repeated prime factors.
        # For two numbers, product is a perfect square iff their cores are equal.
        # So a complete subset can include numbers whose cores are all the same.
        # Then the maximum element-sum is the sum of all nums sharing the most valuable core.

        def squarefree_core(x: int) -> int:
            res = 1
            p = 2
            while p * p <= x:
                if x % p == 0:
                    cnt = 0
                    while x % p == 0:
                        x //= p
                        cnt ^= 1  # parity of exponent
                    if cnt == 1:
                        res *= p
                p += 1 if p == 2 else 2  # check 2 then odd numbers only
            if x > 1:
                # remaining prime factor has exponent 1 (odd)
                res *= x
            return res

        sums = defaultdict(int)
        for v in nums:
            c = squarefree_core(v)
            sums[c] += v

        return max(sums.values())
