from typing import List
import math

class Solution:
    def maximumSum(self, nums: List[int]) -> int:
        # Reduce each number to its parity mask of prime exponents (square-free kernel)
        # Complete subset condition: for any pair (a,b), a*b is a perfect square
        # <=> kernels match. So we can take all numbers with the same kernel.
        # Answer: maximum sum over kernels.

        # Sieve primes up to sqrt(1e9)
        limit = 31623
        is_prime = bytearray(b"\x01") * (limit + 1)
        is_prime[0:2] = b"\x00\x00"
        primes = []
        for i in range(2, limit + 1):
            if is_prime[i]:
                primes.append(i)
                step = i
                start = i * i
                if start <= limit:
                    is_prime[start:limit+1:step] = b"\x00" * ((limit - start)//step + 1)

        def kernel(x: int):
            res = 1
            temp = x
            for p in primes:
                if p * p > temp:
                    break
                if temp % p == 0:
                    cnt = 0
                    while temp % p == 0:
                        temp //= p
                        cnt ^= 1  # only parity matters
                    if cnt:
                        res *= p
            # if leftover prime has odd exponent (it can only be exponent 1 here)
            if temp > 1:
                res *= temp
            return res

        sums = {}
        ans = 0
        for v in nums:
            k = kernel(v)
            new_sum = sums.get(k, 0) + v
            sums[k] = new_sum
            if new_sum > ans:
                ans = new_sum
        return ans
